import{_ as e,c as l,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Clawdbot 完全デプロイメントガイド：ローカル、Docker、Nix、Fly.io、Hetzner VPS、exe.dev | Clawdbot チュートリアル","description":"さまざまなプラットフォームへのClawdbotデプロイメント方法を学習：ローカルインストール、Dockerコンテナ化、Nix宣言型設定、Fly.ioクラウドデプロイメント、Hetzner VPSホスティング、exe.dev仮想ホスティング。各デプロイ方式の特徴、適用シナリオ、設定手順、セキュリティベストプラクティスを解説。","frontmatter":{"title":"Clawdbot 完全デプロイメントガイド：ローカル、Docker、Nix、Fly.io、Hetzner VPS、exe.dev | Clawdbot チュートリアル","sidebarTitle":"Gateway を24時間365日稼働させる","subtitle":"デプロイメントオプション","description":"さまざまなプラットフォームへのClawdbotデプロイメント方法を学習：ローカルインストール、Dockerコンテナ化、Nix宣言型設定、Fly.ioクラウドデプロイメント、Hetzner VPSホスティング、exe.dev仮想ホスティング。各デプロイ方式の特徴、適用シナリオ、設定手順、セキュリティベストプラクティスを解説。","tags":["デプロイメント","インストール","Docker","Nix","クラウドデプロイメント"],"prerequisite":["start-getting-started"],"order":360},"headers":[],"relativePath":"ja/moltbot/moltbot/appendix/deployment/index.md","filePath":"ja/moltbot/moltbot/appendix/deployment/index.md"}'),o={name:"ja/moltbot/moltbot/appendix/deployment/index.md"};function r(n,t,d,s,c,h){return i(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="デプロイメントオプション" tabindex="-1">デプロイメントオプション <a class="header-anchor" href="#デプロイメントオプション" aria-label="Permalink to &quot;デプロイメントオプション&quot;">​</a></h1><h2 id="学習目標" tabindex="-1">学習目標 <a class="header-anchor" href="#学習目標" aria-label="Permalink to &quot;学習目標&quot;">​</a></h2><p>本レッスンを完了すると、以下のことができるようになります：</p><ul><li>ニーズに最適なデプロイメント方式を選択（ローカル、Docker、Nix、クラウドサービス）</li><li>ローカル環境にClawdbotをインストールして実行</li><li>Dockerを使用してGatewayをコンテナ化デプロイ</li><li>Nixで宣言型にClawdbotを管理</li><li>GatewayをFly.io、Hetzner VPS、exe.devにデプロイ</li><li>リモートアクセスとセキュリティベストプラクティスを設定</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>Clawdbotを使用したいが、どのデプロイメント方式を選択すべきか迷っています：</p><ul><li>ローカルインストールは最も簡単だが、PCの電源を切ると使用できない</li><li>クラウドで24時間365日稼働させたいが、どのクラウドサービスが適切か分からない</li><li>設定ミスを恐れており、最も確実なデプロイメント案を探している</li><li>複数デバイスから同じGatewayにアクセスする必要があるが、その実現方法が分からない</li></ul><h2 id="デプロイ方式の活用シナリオ" tabindex="-1">デプロイ方式の活用シナリオ <a class="header-anchor" href="#デプロイ方式の活用シナリオ" aria-label="Permalink to &quot;デプロイ方式の活用シナリオ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>デプロイ方式</th><th>適用シナリオ</th></tr></thead><tbody><tr><td><strong>ローカルインストール</strong></td><td>個人PC、開発テスト、クイックスタート</td></tr><tr><td><strong>Docker</strong></td><td>環境分離、サーバーデプロイ、高速再構築</td></tr><tr><td><strong>Nix</strong></td><td>再現性のあるデプロイ、既存のNixOS/Home Managerユーザー、バージョンのロールバックが必要な場合</td></tr><tr><td><strong>Fly.io</strong></td><td>クラウド24時間365日稼働、自動HTTPS、簡略化された運用</td></tr><tr><td><strong>Hetzner VPS</strong></td><td>独自のVPS、完全な制御、低コスト24時間365日稼働</td></tr><tr><td><strong>exe.dev</strong></td><td>安価なLinuxホスト、VPSの自己設定が不要</td></tr></tbody></table><h2 id="準備事項" tabindex="-1">準備事項 <a class="header-anchor" href="#準備事項" aria-label="Permalink to &quot;準備事項&quot;">​</a></h2><p>開始前に、以下を確認してください：</p><div class="warning custom-block"><p class="custom-block-title">環境要件</p><ul><li>Node.js ≥ 22（ローカルインストールに必須）</li><li>Docker Desktop + Docker Compose v2（Dockerデプロイに必須）</li><li>Nix flakes + Home Manager（Nixデプロイに必須）</li><li>SSHクライアント（クラウドデプロイアクセスに必須）</li><li>基本的なターミナル操作能力（コピー、ペースト、コマンド実行）</li></ul></div><div class="tip custom-block"><p class="custom-block-title">推奨ツール</p><ul><li>Clawdbotを初めて使用する場合は、<a href="./../../start/getting-started/">クイックスタート</a>から開始することをお勧めします</li><li>AIアシスタント（Claude、Cursorなど）の使用により、設定プロセスを加速できます</li><li>API Key（Anthropic、OpenAIなど）とチャネル認証情報を保存してください</li></ul></div><h2 id="デプロイ方式の比較" tabindex="-1">デプロイ方式の比較 <a class="header-anchor" href="#デプロイ方式の比較" aria-label="Permalink to &quot;デプロイ方式の比較&quot;">​</a></h2><h3 id="ローカルインストール" tabindex="-1">ローカルインストール <a class="header-anchor" href="#ローカルインストール" aria-label="Permalink to &quot;ローカルインストール&quot;">​</a></h3><p><strong>適用</strong>：個人PC、開発テスト、クイックスタート</p><p><strong>メリット</strong>：</p><ul><li>✅ 最もシンプルで直接、追加インフラストラクチャ不要</li><li>✅ 起動が高速、デバッグが容易</li><li>✅ 設定変更は即時反映</li></ul><p><strong>デメリット</strong>：</p><ul><li>❌ PCの電源を切ると使用不可</li><li>❌ 24時間365日サービスには不向き</li><li>❌ 複数デバイス同期に追加設定が必要</li></ul><h3 id="dockerデプロイ" tabindex="-1">Dockerデプロイ <a class="header-anchor" href="#dockerデプロイ" aria-label="Permalink to &quot;Dockerデプロイ&quot;">​</a></h3><p><strong>適用</strong>：サーバーデプロイ、環境分離、CI/CD</p><p><strong>メリット</strong>：</p><ul><li>✅ 環境分離、簡単にクリーンアップと再構築</li><li>✅ クロスプラットフォーム統一デプロイ</li><li>✅ サンドボックス分離ツール実行をサポート</li><li>✅ 設定をバージョン管理可能</li></ul><p><strong>デメリット</strong>：</p><ul><li>❌ Dockerの知識が必要</li><li>❌ 初回設定が少し複雑</li></ul><h3 id="nixデプロイ" tabindex="-1">Nixデプロイ <a class="header-anchor" href="#nixデプロイ" aria-label="Permalink to &quot;Nixデプロイ&quot;">​</a></h3><p><strong>適用</strong>：NixOSユーザー、Home Managerユーザー、再現性のあるデプロイが必要</p><p><strong>メリット</strong>：</p><ul><li>✅ 宣言型設定、再現性</li><li>✅ 高速ロールバック（<code>home-manager switch --rollback</code>）</li><li>✅ 全コンポーネントバージョン固定</li><li>✅ Gateway + macOS app + ツール全管理</li></ul><p><strong>デメリット</strong>：</p><ul><li>❌ 学習曲線が急</li><li>❌ Nixエコシステムの理解が必要</li></ul><h3 id="クラウドデプロイ-fly-io-hetzner-exe-dev" tabindex="-1">クラウドデプロイ（Fly.io / Hetzner / exe.dev） <a class="header-anchor" href="#クラウドデプロイ-fly-io-hetzner-exe-dev" aria-label="Permalink to &quot;クラウドデプロイ（Fly.io / Hetzner / exe.dev）&quot;">​</a></h3><p><strong>適用</strong>：24/7オンライン、リモートアクセス、チーム協働</p><p><strong>メリット</strong>：</p><ul><li>✅ 24/7オンライン、ローカルマシンに依存しない</li><li>✅ 自動HTTPS、手動証明書不要</li><li>✅ 高速スケール</li><li>✅ 複数デバイスリモートアクセスをサポート</li></ul><p><strong>デメリット</strong>：</p><ul><li>❌ クラウドサービス費用が必要</li><li>❌ 基本的な運用知識が必要</li><li>❌ データはサードパーティに保存</li></ul><hr>',39)])])}const x=e(o,[["render",r]]);export{u as __pageData,x as default};
